class Solution {
    public String lastSubstring(String s) {
        int i = 0, j = 1, n = s.length();
        while (j < n) {
            int k = 0;
            while (j + k < n && s.charAt(i + k) == s.charAt(j + k)) k++;
            if (j + k < n && s.charAt(i + k) < s.charAt(j + k)) i = (i + k + 1 > j) ? j : i + k + 1;
            j = (j + k + 1 > i) ? j + k + 1 : j + 1;
        }
        return s.substring(i);
    }
}
